import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { ChargeMaintenanceService } from "src/app/shared/services/charge-maintenance-service.service";
import { ToastService } from "src/app/shared/services/toast.service";

@Component({
  selector: "npr-charge-maintainenece",
  templateUrl: "./charge-maintainenece.component.html",
  styleUrls: ["./charge-maintainenece.component.scss"],
})
export class ChargeMaintaineneceComponent implements OnInit {
  chargeForm: FormGroup;
  submitDisab: boolean;
  respData: any;
  index: number;
  editFlag: boolean = true;

  constructor(
    private toastService: ToastService,
    private formBuilder: FormBuilder,
    private chargeMaintenanceService: ChargeMaintenanceService
  ) {}

  ngOnInit(): void {
    this.buildForm("");
    this.chargeMaintenanceService.getIndex().subscribe((index) => {
      if (index.index) {
        this.index = index.index;
        this.onEditCharge(index.index);
      }
    });
  }
  buildForm(item) {
    this.chargeForm = this.formBuilder.group({
      currency: [item ? item.currency : "", Validators.required],
      chargeAmount: [item ? item.chargeAmount : "", Validators.required],
      chargePercentage: [
        item ? item.chargePercentage : "",
        [Validators.required, Validators.max(100), Validators.min(0)]
      ],
      taxAmount: [item ? item.taxAmount : "", Validators.required],
      taxPercentage: [item ? item.taxPercentage : "", [Validators.required, Validators.max(100), Validators.min(0)]],
      inputBy: [item ? item.inputBy : ""],
      inputTime: [item ? item.inputTime : ""],
      recordStatus: [item ? item.recordStatus : ""],
      verifiedOnce: [item ? item.verifiedOnce : ""],
      verifiedBy: [item ? item.verifiedBy : ""],
      verifiedTime: [item ? item.verifiedTime : ""],
      verifiedStatus: [item ? item.verifiedStatus : ""],
      modNo: [item ? item.modNo : ""],
      id: [item ? item.id : ""],
    });
  }
  onSubmittingofChargeMaintenance(value) {
    if(value === 'submit')
    {
    this.chargeMaintenanceService
      .onchargeMaintenanceSubmit(null, this.chargeForm.value)
      .subscribe((chargeMaintenanceResp) => {
        console.log(chargeMaintenanceResp);

        if (chargeMaintenanceResp.currency == null) {
          this.toastService.errorMessage("Record Already Exist", "");
          this.submitDisab = true;
        } else {
          this.submitDisab = true;
          this.toastService.successMessage("Record Saved SuccessFully!", "");
        }
      });
    }
    if(value === 'edit')
    {
    this.chargeMaintenanceService
      .submittingTheEditedRecord( this.chargeForm.value,null)
      .subscribe((chargeMaintenanceResp) => {
        console.log(chargeMaintenanceResp);

        if (!chargeMaintenanceResp) {
          this.toastService.errorMessage("Cannot update the record", "");
          this.submitDisab = true;
        } else {
          this.submitDisab = true;
          this.toastService.successMessage("Record Updated SuccessFully!", "");
        }
      });
    }
  }
  onEditCharge(index) {
    
    this.editFlag=false;
    this.chargeMaintenanceService
      .sendingIdforchargeMaintenanceEdit(index)
      .subscribe((chargeMaintenanceResp) => {
        console.log(chargeMaintenanceResp);
        this.respData = chargeMaintenanceResp;
        this.buildForm(chargeMaintenanceResp);
      });
  }

  onAuthorizingTheRecord() {
    console.log("this is authorzation");
    this.chargeMaintenanceService
      .onAuthofChargeMaintenance(null, this.chargeForm.value.id)
      .subscribe((authResp) => {
        console.log(authResp);
        this.respData = authResp;

        if (this.respData.inputBy != null) {
          this.toastService.successMessage(
            "You authorized the Record!",
            ""
            // type: "success"
          );
        } else {
          this.toastService.errorMessage(
            "Maker cannot authorize the record",
            ""
          );
        }
      });
  }
  onSubmitEditChargeMaintenance(){
    console.log("This is Edit Charge Maintenance");
    this.editFlag=true;
    console.log(this.editFlag); 
  }

  onClosingTheRecord() {
    console.log("this is close");
    this.chargeMaintenanceService
      .onClosingTheRecord(null, this.chargeForm.value.id.id)
      .subscribe((closeResp) => {
        console.log(closeResp);
        this.respData = closeResp;
        if (this.respData.verifiedStatus == "U") {
          this.toastService.errorMessage(
            "Unauthorize Record Cannot be Closed",
            ""
          );
        } else {
          this.toastService.successMessage(
            "Record closed succefully",
            ""
            // type: "success"
          );
        }
      });
  }

  onReopningTheRecord() {
    console.log("this is reopen");
    this.chargeMaintenanceService
      .onReopningTheRecord(null, this.chargeForm.value.id)
      .subscribe((reopnResp) => {
        console.log(reopnResp);
        this.respData = reopnResp;
        this.respData = reopnResp;
        if (this.respData.recordStatus == "O") {
          this.toastService.successMessage(
            "Record opened succefully",
            ""
            // type: "success"
          );
        } else {
          this.toastService.errorMessage("Record cannot be opened ", "");
        }
      });
  }
  onDeletingTheRecord() {
    console.log("this is delete");
    this.chargeMaintenanceService
      .onDeletTheRecord(null, this.chargeForm.value.id)
      .subscribe((deleteResp) => {
        console.log(deleteResp);
        this.respData = deleteResp;

        // console.log(this.chargeMaintenanceDTO.currency);
        if (this.respData.chargeAmount == null) {
          this.toastService.successMessage(
            "Record deleted succefully",
            ""
            // type: "success"
          );
        } else {
          this.toastService.errorMessage("Record cannot be Deleted ", "");
        }
      });
  }
}
